import React, { useEffect, useMemo, useState } from 'react';
import Header from './components/Header';
import Banner from './components/Banner';
import Row from './components/Row';
import Modal from './components/Modal';
import { useFetch } from './hooks/useFetch';
import { Content } from './types/Content';

const App: React.FC = () => {
  const { categories, loading, error, allItems } = useFetch();
  const [featured, setFeatured] = useState<Content | null>(null);
  const [selected, setSelected] = useState<Content | null>(null);
  const [modalOpen, setModalOpen] = useState<boolean>(false);
  const [query, setQuery] = useState<string>('');

  useEffect(() => {
    if (!loading && categories.length > 0) {
      const trending = categories[0]?.items || [];
      const pick = trending[Math.floor(Math.random() * trending.length)];
      setFeatured(pick || null);
    }
  }, [loading, categories]);

  const searchResults = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return [] as Content[];
    return allItems.filter((i) => i.title.toLowerCase().includes(q) || i.genres.join(' ').toLowerCase().includes(q));
  }, [query, allItems]);

  const handleSelect = (item: Content) => {
    setSelected(item);
    setModalOpen(true);
  };

  const handleCloseModal = () => {
    setModalOpen(false);
    setTimeout(() => setSelected(null), 200);
  };

  return (
    <div className="min-h-screen bg-black text-white">
      <Header onSearch={(q) => setQuery(q)} />
      <main className="relative">
        <div className="pb-10">
          <Banner item={featured} onSelect={(i) => handleSelect(i)} />
          <div className="max-w-6xl mx-auto px-4 -mt-16 relative z-10 space-y-8">
            {query && (
              <Row
                title={`Search Results for \"${query}\"`}
                items={searchResults}
                onSelect={(i) => handleSelect(i)}
                accent="blue"
              />
            )}
            {error && (
              <div className="p-4 rounded-xl bg-red-600/20 text-red-300">{error}</div>
            )}
            {loading && (
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                {Array.from({ length: 8 }).map((_, idx) => (
                  <div key={idx} className="h-40 rounded-xl bg-gray-800 animate-pulse" />
                ))}
              </div>
            )}
            {!loading && categories.map((cat) => (
              <Row key={cat.id} title={cat.title} items={cat.items} onSelect={(i) => handleSelect(i)} />
            ))}
          </div>
        </div>
      </main>
      <footer className="border-t border-white/10 mt-10">
        <div className="max-w-6xl mx-auto px-4 py-10 text-sm text-gray-400 flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-2">
            <span className="text-red-600 font-extrabold text-lg">N</span>
            <span className="font-semibold tracking-wide">Netflair</span>
            <span className="text-gray-600">© {new Date().getFullYear()}</span>
          </div>
          <div className="flex items-center gap-4">
            <a href="#" className="hover:text-gray-200 transition">Terms</a>
            <a href="#" className="hover:text-gray-200 transition">Privacy</a>
            <a href="#" className="hover:text-gray-200 transition">Help</a>
          </div>
        </div>
      </footer>
      <Modal open={modalOpen} item={selected} onClose={() => handleCloseModal()} />
    </div>
  );
};

export default App;

