  useEffect(() => {
    const onScroll = () => {
      setSolid(window.scrollY > 30);
    };
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    const id = setTimeout(() => onSearch(query), 250);
    return () => clearTimeout(id);
  }, [query, onSearch]);

  return (
    <header className={`sticky top-0 z-40 transition ${solid ? 'bg-black/80 backdrop-blur border-b border-white/10' : 'bg-gradient-to-b from-black/60 to-transparent'}`}>
