            <div className="w-7 h-7 rounded-md bg-red-600 flex items-center justify-center text-white font-extrabold">N</div>
            <span className="hidden sm:block font-bold tracking-wide">Netflair</span>
          </div>
          <nav className="hidden md:flex items-center gap-5 text-sm text-gray-300">
            <a href="#" className="hover:text-white transition">Home</a>
            <a href="#" className="hover:text-white transition">Series</a>
            <a href="#" className="hover:text-white transition">Films</a>
            <a href="#" className="hover:text-white transition">New & Popular</a>
            <a href="#" className="hover:text-white transition">My List</a>
          </nav>
        </div>
        <div className="flex items-center gap-3">
