            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5"><path fillRule="evenodd" d="M15.53 3.97a.75.75 0 0 1 0 1.06L9.56 11l5.97 5.97a.75.75 0 1 1-1.06 1.06l-6.5-6.5a.75.75 0 0 1 0-1.06l6.5-6.5a.75.75 0 0 1 1.06 0Z" clipRule="evenodd"/></svg>
          </button>
          <button aria-label="Scroll Right" className="p-2 rounded-lg bg-white/10 hover:bg-white/20 transition" onClick={() => scrollBy(1)}>
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5"><path fillRule="evenodd" d="M8.47 3.97a.75.75 0 0 1 1.06 0l6.5 6.5a.75.75 0 0 1 0 1.06l-6.5 6.5a.75.75 0 0 1-1.06-1.06L14.44 11 8.47 5.03a.75.75 0 0 1 0-1.06Z" clipRule="evenodd"/></svg>
