import React, { useEffect, useRef, useState } from 'react';
import { Content } from '../types/Content';

interface ModalProps {
  open: boolean;
  item: Content | null;
  onClose: () => void;
}

const Modal: React.FC<ModalProps> = ({ open, item, onClose }) => {
  const [playing, setPlaying] = useState<boolean>(false);
  const [inList, setInList] = useState<boolean>(false);
  const overlayRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose]);

  useEffect(() => {
    if (!open) setPlaying(false);
  }, [open]);

  if (!open || !item) return null;

  const handleOverlay = (e: React.MouseEvent<HTMLDivElement>) => {
    if (e.target === overlayRef.current) {
      onClose();
    }
  };

  return (
    <div ref={overlayRef} onClick={(e) => handleOverlay(e)} className="fixed inset-0 bg-black/70 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="w-full max-w-3xl rounded-xl overflow-hidden bg-gray-900 shadow-md">
        <div className="relative h-56 md:h-80 bg-black">
          {!playing && (
            <div className="absolute inset-0">
              <img src={item.backdrop} alt={item.title} className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-gray-900 via-transparent to-transparent" />
              <button
                className="absolute left-4 bottom-4 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition shadow-md"
                onClick={() => setPlaying(true)}
              >
                <span className="inline-flex items-center gap-2">
                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5"><path d="M4.5 5.653c0-1.427 1.543-2.33 2.779-1.599l9.238 5.347c1.296.75 1.296 2.62 0 3.37l-9.238 5.348C6.043 18.85 4.5 17.947 4.5 16.52V5.654Z"/></svg>
                  Play Trailer
                </span>
              </button>
            </div>
          )}
          {playing && (
            <video controls autoPlay className="w-full h-full object-cover">
              <source src="https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4" type="video/mp4" />
            </video>
          )}
          <button
            aria-label="Close"
            className="absolute top-3 right-3 p-2 rounded-lg bg-black/60 hover:bg-black/80 transition"
            onClick={() => onClose()}
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-5 h-5 text-white"><path fillRule="evenodd" d="M5.47 5.47a.75.75 0 0 1 1.06 0L12 10.94l5.47-5.47a.75.75 0 1 1 1.06 1.06L13.06 12l5.47 5.47a.75.75 0 1 1-1.06 1.06L12 13.06l-5.47 5.47a.75.75 0 1 1-1.06-1.06L10.94 12 5.47 6.53a.75.75 0 0 1 0-1.06Z" clipRule="evenodd"/></svg>
          </button>
        </div>
        <div className="p-6 space-y-4">
          <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-3">
            <h3 className="text-2xl font-bold">{item.title}</h3>
            <div className="flex items-center gap-2">
              <button className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition" onClick={() => setPlaying(true)}>
                Play
              </button>
              <button
                className={`px-4 py-2 rounded-lg transition ${inList ? 'bg-green-600 hover:bg-green-500' : 'bg-white/10 hover:bg-white/20'} text-white`}
                onClick={() => setInList((v) => !v)}
              >
                {inList ? 'Added' : 'Add to My List'}
              </button>
            </div>
          </div>
          <p className="text-gray-300 leading-relaxed">{item.description}</p>
          <div className="flex flex-wrap items-center gap-4 text-sm text-gray-400">
            <span className="px-2 py-1 rounded bg-white/5">{item.year}</span>
            <span className="px-2 py-1 rounded bg-white/5">Rating {item.rating.toFixed(1)}</span>
            <span className="px-2 py-1 rounded bg-white/5">{item.genres.join(' • ')}</span>
          </div>
          <div className="flex items-center gap-3 pt-2">
            <img src={item.image} alt={item.title} className="w-16 h-24 object-cover rounded-lg" />
            <div className="text-xs text-gray-400">
              <div className="mb-1">More like this coming soon.</div>
              <div className="opacity-80">Stream instantly in HD and 4K where available.</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Modal;

