const shuffle = <T,>(arr: T[]): T[] => {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
};

export const useFetch = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string>('');

  useEffect(() => {
    const timer = setTimeout(() => {
      try {
        const all = [...seed, ...seed.map((s, idx) => ({ ...s, id: `c-${idx}`, title: `${s.title} ${idx % 3 === 0 ? 'Redux' : idx % 3 === 1 ? 'Origins' : 'Beyond'}` }))];
        const cats: Category[] = [
          { id: 'trending', title: 'Trending Now', items: shuffle(all).slice(0, 12) },
          { id: 'top', title: 'Top Rated', items: shuffle(all).slice(0, 12) },
          { id: 'action', title: 'Action & Adventure', items: shuffle(all).slice(0, 12) },
          { id: 'comedy', title: 'Comedies', items: shuffle(all).slice(0, 12) },
          { id: 'docs', title: 'Documentaries', items: shuffle(all).slice(0, 12) }
        ];
        setCategories(cats);
        setLoading(false);
      } catch (e) {
        setError('Failed to load content. Please try again later.');
        setLoading(false);
      }
    }, 600);
    return () => clearTimeout(timer);
  }, []);

  const allItems = categories.flatMap((c) => c.items);

  return { categories, loading, error, allItems };
};

